#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct publication_model { int initialized; int published; int readers; int retired; };

static int worked_cmem_concurrency_atomics_races_3(struct publication_model *state, int request_reclaim) {
  if (state == NULL || (state->published && !state->initialized)) return 0;
  if (request_reclaim && state->readers != 0) return 0;
  if (request_reclaim) state->retired = 1;
  return 1;
}

int main(void) {
  struct publication_model state = { 1, 1, 2, 0 };
  int rejected = worked_cmem_concurrency_atomics_races_3(&state, 1);
  state.readers = 0;
  int accepted = worked_cmem_concurrency_atomics_races_3(&state, 1);
  int invariant = !rejected && accepted && state.retired && 4 > 0;
  printf("reclamation retired=%d invariant=%d\n", state.retired, invariant);
  return invariant ? 0 : 1;
}

